9420 /// Return true if LHS implies RHS (expanded to its components as "R0 RPred R1")
9421 /// is true.  Return false if LHS implies RHS is false. Otherwise, return
9422 /// std::nullopt if we can't infer anything.
9423 static std::optional<bool>
9424 isImpliedCondICmps(const ICmpInst *LHS, CmpPredicate RPred, const Value *R0,
9425                    const Value *R1, const DataLayout &DL, bool LHSIsTrue) {
9426   Value *L0 = LHS->getOperand(0);
9427   Value *L1 = LHS->getOperand(1);
9428 
9429   // The rest of the logic assumes the LHS condition is true.  If that's not the
9430   // case, invert the predicate to make it so.
9431   CmpPredicate LPred =
9432       LHSIsTrue ? LHS->getCmpPredicate() : LHS->getInverseCmpPredicate();
9433 
9434   // We can have non-canonical operands, so try to normalize any common operand
9435   // to L0/R0.
9436   if (L0 == R1) {
9437     std::swap(R0, R1);
9438     RPred = ICmpInst::getSwappedCmpPredicate(RPred);
9439   }
9440   if (R0 == L1) {
9441     std::swap(L0, L1);
9442     LPred = ICmpInst::getSwappedCmpPredicate(LPred);
9443   }
9444   if (L1 == R1) {
9445     // If we have L0 == R0 and L1 == R1, then make L1/R1 the constants.
9446     if (L0 != R0 || match(L0, m_ImmConstant())) {
9447       std::swap(L0, L1);
9448       LPred = ICmpInst::getSwappedCmpPredicate(LPred);
9449       std::swap(R0, R1);
9450       RPred = ICmpInst::getSwappedCmpPredicate(RPred);
9451     }
9452   }
9453 
9454   // See if we can infer anything if operand-0 matches and we have at least one
9455   // constant.
9456   const APInt *Unused;
9457   if (L0 == R0 && (match(L1, m_APInt(Unused)) || match(R1, m_APInt(Unused)))) {
9458     // Potential TODO: We could also further use the constant range of L0/R0 to
9459     // further constraint the constant ranges. At the moment this leads to
9460     // several regressions related to not transforming `multi_use(A + C0) eq/ne
9461     // C1` (see discussion: D58633).
9462     ConstantRange LCR = computeConstantRange(
9463         L1, ICmpInst::isSigned(LPred), /* UseInstrInfo=*/true, /*AC=*/nullptr,
9464         /*CxtI=*/nullptr, /*DT=*/nullptr, MaxAnalysisRecursionDepth - 1);
9465     ConstantRange RCR = computeConstantRange(
9466         R1, ICmpInst::isSigned(RPred), /* UseInstrInfo=*/true, /*AC=*/nullptr,
9467         /*CxtI=*/nullptr, /*DT=*/nullptr, MaxAnalysisRecursionDepth - 1);
9468     // Even if L1/R1 are not both constant, we can still sometimes deduce
9469     // relationship from a single constant. For example X u> Y implies X != 0.
9470     if (auto R = isImpliedCondCommonOperandWithCR(LPred, LCR, RPred, RCR))
9471       return R;
9472     // If both L1/R1 were exact constant ranges and we didn't get anything
9473     // here, we won't be able to deduce this.
9474     if (match(L1, m_APInt(Unused)) && match(R1, m_APInt(Unused)))
9475       return std::nullopt;
9476   }
9477 
9478   // Can we infer anything when the two compares have matching operands?
9479   if (L0 == R0 && L1 == R1)
9480     return isImpliedCondMatchingOperands(LPred, RPred);
9481 
9482   // It only really makes sense in the context of signed comparison for "X - Y
9483   // must be positive if X >= Y and no overflow".
9484   // Take SGT as an example:  L0:x > L1:y and C >= 0
9485   //                      ==> R0:(x -nsw y) < R1:(-C) is false
9486   if ((LPred == ICmpInst::ICMP_SGT || LPred == ICmpInst::ICMP_SGE) &&
