127   case CmpInst::ICMP_SLE:
128     return getNonEmpty(APInt::getSignedMinValue(W), CR.getSignedMax() + 1);
129   case CmpInst::ICMP_UGT: {
130     APInt UMin(CR.getUnsignedMin());
