9549 std::optional<bool>
9550 llvm::isImpliedCondition(const Value *LHS, CmpPredicate RHSPred,
9551                          const Value *RHSOp0, const Value *RHSOp1,
9552                          const DataLayout &DL, bool LHSIsTrue, unsigned Depth) {
9553   // Bail out when we hit the limit.
9554   if (Depth == MaxAnalysisRecursionDepth)
9555     return std::nullopt;
9556 
9557   // A mismatch occurs when we compare a scalar cmp to a vector cmp, for
9558   // example.
9559   if (RHSOp0->getType()->isVectorTy() != LHS->getType()->isVectorTy())
9560     return std::nullopt;
9561 
9562   assert(LHS->getType()->isIntOrIntVectorTy(1) &&
9563          "Expected integer type only!");
9564 
9565   // Match not
9566   if (match(LHS, m_Not(m_Value(LHS))))
9567     LHSIsTrue = !LHSIsTrue;
9568 
9569   // Both LHS and RHS are icmps.
9570   const ICmpInst *LHSCmp = dyn_cast<ICmpInst>(LHS);
9571   if (LHSCmp)
9572     return isImpliedCondICmps(LHSCmp, RHSPred, RHSOp0, RHSOp1, DL, LHSIsTrue);
9573 
9574   /// The LHS should be an 'or', 'and', or a 'select' instruction.  We expect
9575   /// the RHS to be an icmp.
9576   /// FIXME: Add support for and/or/select on the RHS.
9577   if (const Instruction *LHSI = dyn_cast<Instruction>(LHS)) {
9578     if ((LHSI->getOpcode() == Instruction::And ||
9579          LHSI->getOpcode() == Instruction::Or ||
9580          LHSI->getOpcode() == Instruction::Select))
9581       return isImpliedCondAndOr(LHSI, RHSPred, RHSOp0, RHSOp1, DL, LHSIsTrue,
9582                                 Depth);
9583   }
9584   return std::nullopt;
9585 }
